t.script:
var contactSelect = document.getElementById('delivery_contact_select');
if (contactSelect) {
    contactSelect.addEventListener('change', function() {
        var opt = this.options[this.selectedIndex];
        document.getElementById('contact_name_input').value = opt.dataset.name || '';
        document.getElementById('contact_phone_input').value = opt.dataset.phone || '';
    });
}
document.getElementById('add_line').addEventListener('click', function() {
    var tbody = document.getElementById('lines_body');
    var first = tbody.querySelector('tr.order-line');
    var clone = first.cloneNode(true);
    clone.querySelectorAll('select, input').forEach(function(el) { el.value = ''; });
    tbody.appendChild(clone);
    bindRemove(clone);
});
function bindRemove(row) {
    row.querySelector('.remove-line').addEventListener('click', function() {
        if (document.querySelectorAll('tr.order-line').length > 1) row.remove();
    });
}
document.querySelectorAll('tr.order-line').forEach(bindRemove);

(function() {
    var sel = document.getElementById('imp_contact_select');
    if (sel) {
        sel.addEventListener('change', function() {
            var opt = this.options[this.selectedIndex];
            document.getElementById('imp_contact_name').value = opt.dataset.name || '';
            document.getElementById('imp_contact_phone').value = opt.dataset.phone || '';
        });
    }
})();

t.div:

Shows how long your products have been in storage. Data updates daily.
Orange = 30+ days;
Red = 90+ days.

tr.t-attf-style:
#{
                                'background:#fff0f0;' if sa.days_in_stock >= 90 else
                                ('background:#fff8ee;' if sa.days_in_stock >= 30 else '')
                            }

strong.t-attf-style:
#{
                                        'color:#6b1a1a;' if sa.days_in_stock >= 90 else
                                        ('color:#c87c00;' if sa.days_in_stock >= 30 else '')
                                    }
